using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — returns JsonTypeInfo<Person> directly, no cast needed
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> returned metadata for: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded: {info!.Type.Name}");
}

// Now demonstrate the "not available" path using a restricted resolver
var restricted = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()  // resolves everything...
};
// Replace with a resolver that resolves nothing, to show graceful failure
restricted.TypeInfoResolver = new EmptyResolver();

if (restricted.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? missing))
{
    Console.WriteLine($"Unexpected: got info for {missing!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<Person> returned false — metadata not available (no exception!)");
}

// --- Types ---

public record Person(string Name, int Age);

/// A resolver that never resolves any type.
file sealed class EmptyResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) => null;
}
